fn main() {
    let mut v = vec![1, 2, 3, 4];
    let mut even_indices = Vec::new();
    for (i, x) in v.iter().enumerate() {
        if *x % 2 == 0 {
            even_indices.push(i);
        }
    }
    for i in even_indices {
        v.insert(i + 1, v[i]);
    }
}
